function rootEntry(exportsField, subpath) {
  if (typeof exportsField === 'string' || exportsField === null) {
    return subpath === '.' ? exportsField : null;
  }
  if (!exportsField || typeof exportsField !== 'object' || Array.isArray(exportsField)) {
    return null;
  }

  const keys = Object.keys(exportsField);
  if (keys.some((key) => key.startsWith('.'))) {
    return exportsField[subpath] ?? null;
  }
  return subpath === '.' ? exportsField : null;
}

export function resolveExportTarget(
  exportsField,
  { subpath = '.', conditions = ['node', 'import'] } = {}
) {
  if (!Array.isArray(conditions)) {
    throw new TypeError('conditions must be an array');
  }

  const entry = rootEntry(exportsField, subpath);
  if (typeof entry === 'string') {
    return entry.startsWith('./') ? entry : null;
  }
  if (!entry || typeof entry !== 'object' || Array.isArray(entry)) {
    return null;
  }

  const firstTarget = Object.values(entry)[0];
  return typeof firstTarget === 'string' && firstTarget.startsWith('./')
    ? firstTarget
    : null;
}

