import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';

import { resolveExportTarget } from './package-exports.mjs';

function rawFileUrl(absolutePath) {
  const normalized = absolutePath.replaceAll('\\', '/');
  const pathname = normalized.startsWith('/') ? normalized.slice(1) : normalized;
  return `file:///${pathname}`;
}

export async function loadPlugin(packageRoot, options = {}) {
  const manifestPath = resolve(packageRoot, 'package.json');
  const manifest = JSON.parse(await readFile(manifestPath, 'utf8'));
  const target = resolveExportTarget(manifest.exports, {
    subpath: options.subpath ?? '.',
    conditions: options.conditions ?? ['node', 'import']
  });
  if (target === null) {
    throw new Error(`package ${manifest.name ?? '<anonymous>'} has no matching export`);
  }

  const modulePath = resolve(packageRoot, target);
  const namespace = await import(rawFileUrl(modulePath));
  return namespace.default;
}

