import { loadPlugin } from './plugin-loader.mjs';

export class PluginRegistry {
  #active = new Map();

  async activate(name, packageRoot, options = {}) {
    if (typeof name !== 'string' || name.length === 0) {
      throw new TypeError('name must be a non-empty string');
    }
    const plugin = await loadPlugin(packageRoot, options);
    this.#active.set(name, plugin);
    return plugin;
  }

  get(name) {
    return this.#active.get(name) ?? null;
  }
}

