import test from 'node:test';
import assert from 'node:assert/strict';
import { fileURLToPath } from 'node:url';

import { resolveExportTarget } from '../src/package-exports.mjs';
import { loadPlugin } from '../src/plugin-loader.mjs';
import { PluginRegistry } from '../src/plugin-registry.mjs';

test('a package with one entry resolves as before', () => {
  assert.equal(resolveExportTarget('./index.mjs'), './index.mjs');
  assert.equal(
    resolveExportTarget({ '.': './feature.mjs' }),
    './feature.mjs'
  );
});

test('an ordinary vendor package activates through the registry', async () => {
  const packageRoot = fileURLToPath(
    new URL('../fixtures/basic-plugin/', import.meta.url)
  );
  assert.deepEqual(await loadPlugin(packageRoot), {
    name: 'basic',
    runtime: 'node'
  });

  const registry = new PluginRegistry();
  const plugin = await registry.activate('basic', packageRoot);
  assert.strictEqual(registry.get('basic'), plugin);
});
